<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Snake</title>
<style>
  body{margin:0;background:#111;color:#eee;font-family:sans-serif;text-align:center;}
  #controls{margin-top:10px;}
  button{margin:0 5px;padding:5px 10px;font-size:16px;}
  #score{font-size:18px;margin-left:20px;}
  canvas{border:1px solid #444;background:#111;display:block;margin:auto;}
</style>
</head>
<body>

<canvas id="snake" width="400" height="400"></canvas>
<div id="controls">
  <button id="start">Start</button>
  <button id="pause">Pause</button>
  <button id="reset">Reset</button>
  <span id="score">Score: 0</span>
</div>

<script>
(() => {
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');

  // Grid size
  const w = 20, h = 20; // >=10
  const cellSize = canvas.width / w;

  let snakeArr = []; // [x,y] head first
  let foodPos = null;
  let dir = 'right';
  let nextDir = 'right';
  let aliveFlag = true;
  let scoreVal = 0;
  let intervalId = null;

  function init() {
    snakeArr = [];
    for (let i = 3; i > 0; --i) snakeArr.push([i, Math.floor(h/2)]);
    dir = nextDir = 'right';
    aliveFlag = true;
    scoreVal = 0;
    placeFood();
    draw();
    updateScore();
  }

  function placeFood() {
    const free = [];
    for (let x=0;x<w;++x)for(let y=0;y<h;++y){
      if (!snakeArr.some(s=>s[0]===x&&s[1]===y)) free.push([x,y]);
    }
    if(free.length===0){foodPos=null;return;}
    foodPos = free[Math.floor(Math.random()*free.length)];
  }

  function draw() {
    ctx.fillStyle='#111';
    ctx.fillRect(0,0,canvas.width,canvas.height);
    // snake
    ctx.fillStyle='#4caf50';
    for(const [x,y] of snakeArr){
      ctx.fillRect(x*cellSize,y*cellSize,cellSize,cellSize);
    }
    // food
    if(foodPos){
      ctx.fillStyle='#f44336';
      const [fx,fy]=foodPos;
      ctx.fillRect(fx*cellSize,fy*cellSize,cellSize,cellSize);
    }
  }

  function updateScore(){scoreEl.textContent='Score: '+scoreVal;}

  function tick() {
    if(!aliveFlag)return;
    dir = nextDir;
    const [hx,hy] = snakeArr[0];
    let nx=hx, ny=hy;
    switch(dir){
      case 'up':ny--;break;
      case 'down':ny++;break;
      case 'left':nx--;break;
      case 'right':nx++;break;
    }
    // wall collision
    if(nx<0||nx>=w||ny<0||ny>=h){aliveFlag=false;draw();return;}
    // self collision
    if(snakeArr.some((s,i)=>i>0 && s[0]===nx && s[1]===ny)){aliveFlag=false;draw();return;}
    const ate = foodPos && foodPos[0]==nx && foodPos[1]==ny;
    snakeArr.unshift([nx,ny]);
    if(!ate) snakeArr.pop();
    if(ate){
      scoreVal++;
      updateScore();
      placeFood();
    }
    draw();
  }

  // API
  window.game = {
    w,h,
    reset: init,
    tick,
    setDir(d){if(['up','down','left','right'].includes(d)){
        const opp={'up':'down','down':'up','left':'right','right':'left'};
        if(opp[dir]!==d) nextDir=d;
      }},
    setFood(x,y){
      if(x>=0&&x<w&&y>=0&&y<h && !snakeArr.some(s=>s[0]===x&&s[1]===y)){
        foodPos=[x,y];
        draw();
      }
    },
    snake:()=>snakeArr.slice(),
    food:()=>foodPos?foodPos.slice():null,
    alive:()=>aliveFlag,
    score:()=>scoreVal
  };

  // Controls
  document.getElementById('start').onclick=()=>{
    if(intervalId)return;
    intervalId=setInterval(tick,200);
  };
  document.getElementById('pause').onclick=()=>{
    clearInterval(intervalId);intervalId=null;
  };
  document.getElementById('reset').onclick=()=>{clearInterval(intervalId);intervalId=null;init();};

  // Keyboard
  window.addEventListener('keydown',e=>{
    switch(e.key){
      case 'ArrowUp':game.setDir('up');break;
      case 'ArrowDown':game.setDir('down');break;
      case 'ArrowLeft':game.setDir('left');break;
      case 'ArrowRight':game.setDir('right');break;
    }
  });

  init();
})();
</script>
</body>
</html>
